import{c as a,S as e,j as r,m as o}from"./chunks/framework.DvQr6YbT.js";const b=JSON.parse('{"title":"授权","description":"","frontmatter":{},"headers":[],"relativePath":"zh/sharing/grant-access.md","filePath":"zh/sharing/grant-access.md","lastUpdated":1783414742000}'),s={name:"zh/sharing/grant-access.md"};function d(n,t,i,l,h,c){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="授权" tabindex="-1">授权 <a class="header-anchor" href="#授权" aria-label="Permalink to “授权”">​</a></h1><p><strong>发布不等于授权。</strong>私有仓库里的 Release 对没有读权限的人完全不可见——GitHub 返回 404，连仓库是否存在都不确认。因此每次发布都以一条<em>受众声明</em>结尾，告诉你谁能安装； 本页是&quot;如何改变这一点&quot;的配套说明。</p><table tabindex="0"><thead><tr><th>知识包在哪里</th><th>谁能安装</th><th>如何授权</th></tr></thead><tbody><tr><td>你<strong>组织</strong>下的私有仓库</td><td>有读权限的成员</td><td>组织 base permission 设为 Read 即覆盖全员；细粒度用 org team</td></tr><tr><td>你<strong>个人</strong>的私有仓库</td><td>只有你和 collaborators</td><td>仓库 → Settings → Collaborators → 邀请（对方需接受）</td></tr><tr><td><strong>公开</strong>仓库</td><td>任何拿到链接的人</td><td>无需操作——这既是意义所在，也是风险所在</td></tr></tbody></table><h2 id="组织货架-团队推荐" tabindex="-1">组织货架（团队推荐） <a class="header-anchor" href="#组织货架-团队推荐" aria-label="Permalink to “组织货架（团队推荐）”">​</a></h2><p>在你们的 GitHub 组织下建一个私有仓库——比如 <code>your-org/kb-bundles</code>——组织 base permission 设为 <strong>Read</strong>：</p><ul><li>每位成员用自己的 GitHub 登录安装，无需逐人逐包管理。</li><li>权限跟随成员身份：入组即获得，离组即失效。</li><li>团队任何人都可以向同一货架发布——它自然成为团队知识中心。</li></ul><p>GitHub 免费版即可（私有仓库与成员数均不限）。</p><h2 id="接收者一侧" tabindex="-1">接收者一侧 <a class="header-anchor" href="#接收者一侧" aria-label="Permalink to “接收者一侧”">​</a></h2><p>有权限还不够——接收者下载时必须处于<em>已认证</em>状态：CLI 路径需要 <code>gh auth login</code>， 手动路径需要浏览器已登录。最常见的困惑正是这个：参见 <a href="./troubleshooting">&quot;链接 404&quot;</a>。</p>',9)])])}const p=a(s,[["render",d]]);export{b as __pageData,p as default};
